#include <iostream>
#include <vector>
#include <string>

using namespace std;

// ==========================================
// 1. АБСТРАКТНИЙ БАЗОВИЙ КЛАС
// ==========================================
class Asset {
protected:
    string name;
    double price;

public:
    Asset(string n, double p) : name(n), price(p) {}

    // Віртуальний деструктор - обов'язково для поліморфізму!
    virtual ~Asset() {
        cout << "[Asset] Знищення базового активу: " << name << endl;
    }

    // Чисто віртуальна функція (= 0)
    // Робить клас абстрактним - ми не можемо створити просто об'єкт Asset
    virtual void analyze() const = 0;

    string getName() const { return name; }
};

// ==========================================
// 2. ПОХІДНИЙ КЛАС 1: Акція
// ==========================================
class Stock : public Asset {
private:
    double dividendYield;

public:
    Stock(string n, double p, double yield) : Asset(n, p), dividendYield(yield) {}

    void analyze() const override {
        cout << "[Аналіз Stock] Акція: " << name << " | Ціна: $" << price
             << " | Дивіденди: " << dividendYield << "% -> Оцінка: Стабільно." << endl;
    }

    ~Stock() override {
        cout << "[Stock] Знищення акції: " << name << endl;
    }
};

// ==========================================
// 3. ПОХІДНИЙ КЛАС 2: Криптовалюта
// ==========================================
class Crypto : public Asset {
private:
    double volatility;

public:
    Crypto(string n, double p, double vol) : Asset(n, p), volatility(vol) {}

    void analyze() const override {
        cout << "[Аналіз Crypto] Крипта: " << name << " | Ціна: $" << price
             << " | Волатильність: " << volatility << "% -> Оцінка: Високий ризик!" << endl;
    }

    ~Crypto() override {
        cout << "[Crypto] Знищення криптовалюти: " << name << endl;
    }
};

int main() {
    cout << "--- Запуск системи Market Oracle ---\n\n";

    // STL Контейнер: Вектор вказівників на базовий клас
    vector<Asset*> portfolio;

    // Додаємо об'єкти різних класів у один контейнер!
    portfolio.push_back(new Stock("Apple Inc.", 175.50, 0.5));
    portfolio.push_back(new Crypto("Bitcoin", 64000.00, 4.2));
    portfolio.push_back(new Stock("NVIDIA", 850.20, 0.1));

    cout << "Аналіз портфелю активів:\n";
    // Поліморфізм у дії: один цикл, різні результати
    for (Asset* asset : portfolio) {
        asset->analyze();
    }

    cout << "\n--- Очищення пам'яті ---\n";
    for (Asset* asset : portfolio) {
        delete asset;
    }
    portfolio.clear();

    return 0;
}
